let contexts: any[] = [];

// View stored documents first to see what metadata is actually stored!
try {
  console.error("Viewing stored documents...");
  const viewRes = await client.v1.context.view.docs();
  console.error("Stored documents:", JSON.stringify(viewRes.documents, null, 2));
} catch (err: any) {
  console.error("View docs failed:", err.message || err);
}

// Method A: Using body_metadata
try {
  console.error("Trying Method A (body_metadata)...");
  const resA = await client.v1.context.search({
    query: "engineering product version notes Key",
    scope: 'internal',
    similarity_threshold: 0.1,
    minimum_similarity_threshold: 0.1,
    body_metadata: {
      groupName: groups
    }
  } as any);
  const keysA = new Set();
  for (const ctx of resA.contexts || []) {
    for (const k of ["ENG_V1_DOC", "ENG_V2_DOC", "PRODUCT_V1_DOC", "PRODUCT_V2_DOC"]) {
      if (ctx.content && ctx.content.includes(k)) keysA.add(k);
    }
  }
  console.error(`Method A success! Found ${(resA.contexts || []).length} contexts. Matched keys: ${Array.from(keysA).join(', ')}`);
  if ((resA.contexts || []).length > 0) {
    contexts = resA.contexts || [];
  }
} catch (err: any) {
  console.error("Method A failed:", err.message || err);
}

// Method B: Bypassing SDK search and posting directly with metadata in body
try {
  console.error("Trying Method B (direct POST with metadata)...");
  const resB: any = await (client as any).post('/api/v1/context/search', {
    body: {
      query: "engineering product version notes Key",
      scope: 'internal',
      similarity_threshold: 0.1,
      minimum_similarity_threshold: 0.1,
      metadata: {
