      if (ctx.content && ctx.content.includes(k)) keysB.add(k);
    }
  }
  console.error(`Method B success! Found ${(resB.contexts || []).length} contexts. Matched keys: ${Array.from(keysB).join(', ')}`);
  if (contexts.length === 0 && (resB.contexts || []).length > 0) {
    contexts = resB.contexts || [];
  }
} catch (err: any) {
  console.error("Method B failed:", err.message || err);
}

